export function getCitiesByCountry(countrySlug: string): CountryCity[] {
  return countryCityContent.filter((c) => c.countrySlug === countrySlug);
}

export function getCountryCity(countrySlug: string, citySlug: string): CountryCity | undefined {
  return countryCityContent.find((c) => c.countrySlug === countrySlug && c.citySlug === citySlug);
}

export function getRelatedCountryCities(citySlug: string, countrySlug: string): CountryCity[] {
  return countryCityContent.filter((c) => c.countrySlug === countrySlug && c.citySlug !== citySlug).slice(0, 4);
}

// Country slugs that currently have rich city-page content (phase 1: major European markets).
export const COUNTRIES_WITH_CITY_PAGES: string[] = Array.from(
  new Set(countryCityContent.map((c) => c.countrySlug)),
);
